const body = $input.first().json;
const url = (body.url || body.link || '').toString().trim();
if (!url) throw new Error('No URL in body');

let platform = 'unknown';
if (url.includes('tidal.com'))      platform = 'tidal';
else if (url.includes('qobuz.com'))      platform = 'qobuz';
else if (url.includes('deezer.com'))     platform = 'deezer';
else if (url.includes('spotify.com'))    platform = 'spotify';
else if (url.includes('apple.com'))      platform = 'apple';
else if (url.includes('soundcloud.com')) platform = 'soundcloud';
else if (url.includes('youtube.com') || url.includes('youtu.be')) platform = 'youtube';

return [{ json: { url, platform } }];

const lucida   = $input.first().json;
const platform = $('Extract Platform').first().json.platform;

const downloadUrl =
  lucida?.url ||
  lucida?.result?.url ||
  lucida?.download_url ||
  lucida?.data?.url ||
  null;

const meta   = lucida?.result?.metadata || lucida?.metadata || {};
const title  = meta.title  || lucida?.title  || 'Unknown Title';
const artist = meta.artist || lucida?.artist || '';

return [{
  json: {
    status:       downloadUrl ? 'ok' : 'error',
    platform,
    download_url: downloadUrl,
    metadata:     { title, artist },
    message:      downloadUrl ? null : 'Lucida could not find a link for this URL'
  }
}];
